const src = $json;

function toText(value) {
  if (value == null) return "";
  if (typeof value === "string") return value;
  if (Array.isArray(value)) return value.map(v => toText(v)).join("\n");
  return String(value);
}

const mergedMessages = toText(
  src.mensagens ||
  src.messages ||
  src.conversa ||
  src.message?.text ||
  ""
)
  .replace(/\s+/g, " ")
  .trim();

const out = {
  ticket_id: src.ticket_id || src.ticket?.id || src.conversation_id || `WT-${Date.now()}`,
  cliente:
    src.cliente ||
    src.contact?.name ||
    src.contact?.phoneNumber ||
    src.customer?.name ||
    "Cliente sem nome",
  mensagens: mergedMessages || "[sem mensagens relevantes]",
  data_evento: src.data_evento || src.timestamp || new Date().toISOString(),
  canal:
    src.canal ||
    (src.contact?.phoneNumber ? "whatsapp" : "telefone"),
  tecnico: src.tecnico || src.ticket?.assignee?.name || ""
};

const eventName = src.event || src.event_type || "evt";
out.idempotency_key = `${out.ticket_id}:${eventName}:${out.data_evento}`;

return [{ json: out }];
